-- DATASOURCE: dbi:Oracle:host=192.168.101.29;sid=pean;port=1521

SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_tel_det_coll_garantee (membership_no, mem_name, member_group_no, member_group_name, loan_contract_no, coll_no, coll_name, coll_group_no, coll_group_name, principal_balance) AS SELECT sc_mem_m_membership_registered.membership_no
    , pka_com_function.fp_get_member_name( sc_mem_m_membership_registered.membership_no ) as mem_name
    , sc_mem_m_membership_registered.member_group_no
    , sc_mem_m_ucf_member_group.member_group_name

    , sc_lon_m_loan_card.loan_contract_no
    
    , CASE WHEN  sc_lon_m_ucf_collateral_type.collateral_type_code  ='01' THEN  sc_lon_m_contract_coll.ref_own_no   ELSE sc_lon_m_ucf_collateral_type.collateral_description END   AS COLL_NO
    , CASE WHEN  sc_lon_m_ucf_collateral_type.collateral_type_code  ='01' THEN  sc_lon_m_contract_coll.collateral_description   ELSE sc_lon_m_contract_coll.collateral_description END   AS COLL_NAME
    
    
    , CASE WHEN  sc_lon_m_ucf_collateral_type.collateral_type_code          ='01' THEN ( select sc_mem_m_ucf_member_group.member_group_no                     FROM sc_mem_m_membership_registered                     ,sc_mem_m_ucf_member_group                    where  sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no                    and sc_mem_m_membership_registered.membership_no = sc_lon_m_contract_coll.ref_own_no )           ELSE '' END   AS COLL_GROUP_NO
    
    , CASE WHEN  sc_lon_m_ucf_collateral_type.collateral_type_code          ='01' THEN (  select sc_mem_m_ucf_member_group.member_group_name                    from sc_mem_m_membership_registered                     ,sc_mem_m_ucf_member_group                    where  sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no                    and sc_mem_m_membership_registered.membership_no = sc_lon_m_contract_coll.ref_own_no )           ELSE '' END   AS COLL_GROUP_NAME

   
        , sc_lon_m_loan_card.principal_balance   
      
    FROM sc_lon_m_loan_card,   
         sc_lon_m_contract_coll,   
         sc_lon_m_ucf_collateral_type,   
         sc_mem_m_membership_registered  
        ,sc_mem_m_ucf_member_group
        ,sc_lon_m_rule
   WHERE 1=1
   AND  sc_lon_m_rule.loan_type = sc_lon_m_loan_card.loan_type
   AND   sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract_coll.loan_contract_no
   AND   sc_lon_m_contract_coll.collateral_type_code = sc_lon_m_ucf_collateral_type.collateral_type_code  
   AND   sc_lon_m_loan_card.membership_no = sc_mem_m_membership_registered.membership_no 
   AND   sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no   
   AND (  sc_lon_m_loan_card.principal_balance > 0 or (  sc_lon_m_rule.atm_status = '1' and  sc_lon_m_loan_card.close_status = '0' ) )  
   AND   sc_lon_m_contract_coll.status = '0'    
   
   /*AND   sc_lon_m_loan_card.membership_no in  ( '011239' , '008794' , '001320' )  */

 
ORDER BY    sc_mem_m_membership_registered.membership_no
,sc_lon_m_loan_card.loan_contract_no
,sc_lon_m_contract_coll.collateral_type_code
,sc_lon_m_contract_coll.ref_own_no;

